        MockMultipartFile payload = new MockMultipartFile(
            "payload",
            "payload.json",
            MULTIPART_FORM_DATA.toString(),
            json(java.util.Map.of(
                "documentTypeId", type.getId(),
                "title", "Controlled PNG",
